#ifndef BOOT_PROTO_H
#define BOOT_PROTO_H

#include <stdint.h>

#define BOOT_CMD_ERASE      0x01U
#define BOOT_CMD_WRITE      0x02U
#define BOOT_CMD_READ       0x03U
#define BOOT_CMD_VERIFY     0x04U
#define BOOT_CMD_RESET      0x05U
#define BOOT_CMD_GET_INFO   0x06U

#define BOOT_ACK            0xAAU
#define BOOT_NACK           0x55U

#define BOOT_MAX_PAYLOAD    256U

typedef struct {
    uint8_t  cmd;
    uint16_t length;
    uint8_t  payload[BOOT_MAX_PAYLOAD];
    uint8_t  checksum;
} Boot_Packet_t;

int Boot_SendPacket(Boot_Packet_t *pkt);
